    var lCount = 0L
    var cCount = 0L
    var tCount = 0L

    for (char in s) {
        when (char) {
            'L' -> lCount++
            'C' -> cCount += lCount
            'T' -> tCount += cCount
        }
    }
    originalCount = tCount

    val n = s.length
    val prefixL = LongArray(n + 1)
    for (i in 0 until n) {
        prefixL[i + 1] = prefixL[i] + if (s[i] == 'L') 1 else 0
    }

    val suffixT = LongArray(n + 1)
    for (i in n - 1 downTo 0) {
        suffixT[i] = suffixT[i + 1] + if (s[i] == 'T') 1 else 0
    }

    var maxCInsert = 0L
    for (i in 0..n) {
        val lBefore = prefixL[i]
        val tAfter = suffixT[i]
        val current = lBefore * tAfter
        if (current > maxCInsert) {
            maxCInsert = current
        }
    }
    val bestCIncrease = maxCInsert

    var totalCT = 0L
    var tSoFar = 0L
    for (i in n - 1 downTo 0) {
        when (s[i]) {
            'T' -> tSoFar++
            'C' -> totalCT += tSoFar
        }
